    "schemaContext": ["https://raw.githubusercontent.com/beckn/DDM/main/specification/schema/DatasetItem/v1/context.jsonld"]
  },
  "message": {
    "contract": {
      "id": "660e9500-f30c-52e5-b827-557766551300",
      "descriptor": {
        "name": "ARR Filing Data Exchange",
        "shortDesc": "ARR filing submission under regulatory mandate"
      },
      "status": {
        "code": "ACTIVE"
      },
      "commitments": [
        {
          "id": "commitment-arr-filing-001",
          "status": {
            "descriptor": {
              "code": "ACTIVE"
            }
          },
          "resources": [
            {
              "id": "ds-bescom-arr-filing-fy2025-26",
              "descriptor": {
                "name": "BESCOM ARR Filing - FY 2025-26"
              },
              "quantity": {
                "unitText": "filing",
                "unitCode": "EA",
                "value": "1"
              }
            }
          ],
          "offer": {
            "id": "offer-arr-filing-inline",
            "descriptor": {
              "name": "ARR Filing Inline Delivery - BESCOM FY 2025-26"
            },
            "resourceIds": ["ds-bescom-arr-filing-fy2025-26"]
          },
          "commitmentAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/DDM/main/specification/schema/DatasetItem/v1/context.jsonld",
            "@type": "DatasetItem",
            "schema:identifier": "ds-bescom-arr-filing-fy2025-26",
            "schema:name": "BESCOM ARR Filing - FY 2025-26",
            "schema:temporalCoverage": "2025-04-01/2026-03-31",
            "dataset:accessMethod": "INLINE"
          }
        }
      ],
      "consideration": [
        {
          "id": "consideration-arr-regulatory-mandate",
          "status": {
            "code": "ACTIVE"
          },
          "considerationAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/schemas/refs/heads/main/schema/PriceSpecification/v2.1/context.jsonld",
            "@type": "PriceSpecification",
            "currency": "INR",
            "value": 0,
            "description": "Mandatory regulatory filing - no commercial consideration"
          }
        }
      ],
      "participants": [
        {"id": "bescom-discom-001", "descriptor": {"name": "BESCOM - Bangalore Electricity Supply Company"}},
        {"id": "aperc-regulator-001", "descriptor": {"name": "APERC - AP Electricity Regulatory Commission"}}
      ],
      "performance": [],
      "settlements": [
        {
          "id": "settlement-payment-completed",
          "considerationId": "consideration-arr-regulatory-mandate",
          "status": "COMPLETE",
          "settlementAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/schemas/refs/heads/main/schema/Payment/v2.0/context.jsonld",
            "@type": "Payment",
            "beckn:paymentStatus": "COMPLETED",
            "beckn:amount": {
              "currency": "INR",
              "value": 0
            }
          }
        }
      ]
    }
  }
}

{
  "context": {
